#!/usr/bin/env bash
# test_bulkrnaseq.sh — TJP test module for the BulkRNASeq pipeline
# Sourced by the test framework (tjp-test-suite). Do not execute directly.

PIPELINE_NAME="bulkrnaseq"
L3_SKIP=false
L3_SKIP_REASON=""

# Synthetic FASTQ dir generated by generate_rnaseq_synthetic.sh
_BULKRNASEQ_SYNTHETIC_DIR="$SCRATCH_ROOT/pipelines/bulkrnaseq/test_data/fastq"
_BULKRNASEQ_TINY_STAR="$REPO_ROOT/references/tiny/star_index"

# ── Layer 1: offline validation ───────────────────────────────────────────────

l1_bulkrnaseq() {
    local schema="$REPO_ROOT/templates/schemas/bulkrnaseq.yaml"
    local tmpl="$REPO_ROOT/templates/bulkrnaseq/config.yaml"
    local ss_tmpl="$REPO_ROOT/templates/bulkrnaseq/samplesheet.csv"
    local tmpdir
    tmpdir=$(mktemp -d)

    # Schema and template files exist
    ts_assert_exists "bulkrnaseq schema exists" "$schema"
    ts_assert_exists "bulkrnaseq template config exists" "$tmpl"
    ts_assert_exists "bulkrnaseq samplesheet template exists" "$ss_tmpl"

    # Required keys present in template
    for key in project_name species paired_end fastq_dir samples_file \
               star_index reference_gtf run_fastqc run_rna_pipeline; do
        ts_assert_yaml_key "template has '$key'" "$tmpl" "$key"
    done

    # Samplesheet template has required columns
    ts_assert_contains "samplesheet has 'sample' column"   "$ss_tmpl" "sample"
    ts_assert_contains "samplesheet has 'fastq_1' column"  "$ss_tmpl" "fastq_1"
    ts_assert_contains "samplesheet has 'fastq_2' column"  "$ss_tmpl" "fastq_2"

    # Build a good config (use /path/to/ placeholders so path-existence checks
    # in the validator are skipped for reference files)
    local good_cfg="$tmpdir/good_config.yaml"
    cat > "$good_cfg" <<YAML
project_name: Test-BulkRNASeq
species: Human
paired_end: true
fastq_dir: /path/to/fastq
samples_file: /path/to/samples.txt
star_index: /path/to/star_index
reference_gtf: /path/to/gencode.gtf
run_fastqc: true
run_rna_pipeline: true
YAML
    ts_assert_pass "valid config passes validator" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && source '$REPO_ROOT/bin/lib/validate.sh' && validate_config bulkrnaseq '$good_cfg'"

    # Missing star_index must fail
    local bad_cfg="$tmpdir/bad_no_star.yaml"
    cat > "$bad_cfg" <<YAML
project_name: Test-BulkRNASeq
species: Human
paired_end: true
fastq_dir: /path/to/fastq
samples_file: /path/to/samples.txt
reference_gtf: /path/to/gencode.gtf
run_fastqc: true
run_rna_pipeline: true
YAML
    ts_assert_fail "config missing 'star_index' fails validator" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && source '$REPO_ROOT/bin/lib/validate.sh' && validate_config bulkrnaseq '$bad_cfg'"

    # Missing samples_file must fail
    local bad_cfg2="$tmpdir/bad_no_samples.yaml"
    cat > "$bad_cfg2" <<YAML
project_name: Test-BulkRNASeq
species: Human
paired_end: true
fastq_dir: /path/to/fastq
star_index: /path/to/star_index
reference_gtf: /path/to/gencode.gtf
run_fastqc: true
run_rna_pipeline: true
YAML
    ts_assert_fail "config missing 'samples_file' fails validator" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && source '$REPO_ROOT/bin/lib/validate.sh' && validate_config bulkrnaseq '$bad_cfg2'"

    rm -rf "$tmpdir"
}

# ── Layer 2: dry-run launch ───────────────────────────────────────────────────

l2_bulkrnaseq() {
    local tmpdir
    tmpdir=$(mktemp -d)
    local fastq_dir="$tmpdir/fastq"
    local samples_txt="$tmpdir/samples.txt"
    mkdir -p "$fastq_dir"
    echo "Sample_A" > "$samples_txt"

    local cfg="$tmpdir/config.yaml"
    cat > "$cfg" <<YAML
project_name: BulkRNASeq-L2-Test
species: Human
paired_end: true
fastq_dir: $fastq_dir
samples_file: $samples_txt
star_index: /path/to/star_index
reference_gtf: /path/to/gencode.gtf
run_fastqc: false
run_rna_pipeline: true
YAML

    # Config validates (paths with /path/to/ prefix are skipped by validator)
    ts_assert_pass "l2: config validates" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && source '$REPO_ROOT/bin/lib/validate.sh' && validate_config bulkrnaseq '$cfg'"

    # SLURM template and pipeline are wired in the registry
    ts_assert_pass "l2: bulkrnaseq in KNOWN_PIPELINES" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && is_known_pipeline bulkrnaseq"

    ts_assert_pass "l2: SLURM template resolves" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && [[ -f \$(get_slurm_template bulkrnaseq) ]]"

    ts_assert_fail "l2: bulkrnaseq is not a native pipeline" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && is_native_pipeline bulkrnaseq"

    # Nextflow pipeline.config template must exist (required by tjp-launch bulkrnaseq)
    ts_assert_exists "l2: Nextflow pipeline.config.tmpl exists" \
        "$REPO_ROOT/templates/bulkrnaseq/pipeline.config.tmpl"

    rm -rf "$tmpdir"
}

# ── Layer 3: full SLURM execution ─────────────────────────────────────────────

l3_fixture_bulkrnaseq() {
    if [[ ! -d "$_BULKRNASEQ_SYNTHETIC_DIR" ]]; then
        echo "Synthetic FASTQ dir not found: $_BULKRNASEQ_SYNTHETIC_DIR" >&2
        echo "Run: $REPO_ROOT/test_data/fixtures/generate_rnaseq_synthetic.sh $(dirname "$_BULKRNASEQ_SYNTHETIC_DIR")" >&2
        return 1
    fi

    local count
    count=$(find "$_BULKRNASEQ_SYNTHETIC_DIR" -name "*.fastq.gz" | wc -l)
    if [[ "$count" -eq 0 ]]; then
        echo "No .fastq.gz files in $_BULKRNASEQ_SYNTHETIC_DIR" >&2
        return 1
    fi

    if [[ ! -d "$_BULKRNASEQ_TINY_STAR" ]]; then
        echo "Tiny STAR index not found: $_BULKRNASEQ_TINY_STAR" >&2
        echo "Build one with STAR --runMode genomeGenerate against a tiny reference." >&2
        return 1
    fi

    return 0
}

l3_submit_bulkrnaseq() {
    local test_dir="$TEST_SCRATCH/bulkrnaseq"
    local cfg="$test_dir/config_bulkrnaseq.yaml"
    local samples_file="$test_dir/samples.txt"
    mkdir -p "$test_dir"

    # Build samples.txt from synthetic FASTQs (R1 files → sample names)
    for f in "$_BULKRNASEQ_SYNTHETIC_DIR"/*_R1_001.fastq.gz; do
        basename "$f" _R1_001.fastq.gz
    done > "$samples_file"

    cat > "$cfg" <<YAML
project_name: BulkRNASeq-L3-Test
species: Human
paired_end: true
fastq_dir: $_BULKRNASEQ_SYNTHETIC_DIR
samples_file: $samples_file
star_index: $_BULKRNASEQ_TINY_STAR
reference_gtf: /path/to/gencode.gtf
run_fastqc: false
run_rna_pipeline: true
YAML

    local job_id
    job_id=$("$REPO_ROOT/bin/tjp-launch" bulkrnaseq --dev --config "$cfg" 2>/dev/null \
        | grep -oP '(?<=job )\d+' | tail -1)
    echo "$job_id"
}

l3_validate_bulkrnaseq() {
    # Find the most recent run directory for bulkrnaseq
    local runs_dir="$WORK_ROOT/pipelines/bulkrnaseq/runs"
    local latest_run
    latest_run=$(ls -1td "$runs_dir"/*/  2>/dev/null | head -1)

    if [[ -z "$latest_run" ]]; then
        ts_assert_exists "bulkrnaseq: run directory exists" "$runs_dir"
        return
    fi

    ts_assert_exists  "bulkrnaseq: run dir created"     "$latest_run"
    ts_assert_exists  "bulkrnaseq: config snapshot"     "$latest_run/config.yaml"
    ts_assert_exists  "bulkrnaseq: manifest.json"       "$latest_run/manifest.json"
    ts_assert_exists  "bulkrnaseq: outputs/2_star_mapping_output" \
                      "$latest_run/outputs/2_star_mapping_output"
    ts_assert_exists  "bulkrnaseq: outputs/5_raw_counts_output" \
                      "$latest_run/outputs/5_raw_counts_output"
}

l3_teardown_bulkrnaseq() {
    :
}
